sql:
SELECT MIN(exoplanet_id)
FROM exoplanet_characteristics
WHERE characteristic_name = 'surface_temperature';

SELECT mass 
  FROM exoplanets 
  WHERE exoplanet_id = 1;

external_knowledge:
External knowledge: 
1. 'Massive' refers to the mass of the exoplanet in Jupiter units; 
2. 'Lightweight' in this context means a mass less than 10 Jupiter units; 
3. 'Most tilted orbits' corresponds to the highest inclination in the exoplanet orbits; 
4. 'Exoplanets' refer to planets outside the solar system.

sql:
SELECT R.researcher_id, R.researcher_name
FROM researchers AS R
WHERE R.researcher_affiliation = 'NASA' AND R.expertise = 'Orbital Dynamics';

SELECT mass 
FROM exoplanets 
ORDER BY mass DESC;

SELECT exoplanet_id, eccentricity, orbital_period
FROM exoplanets
WHERE eccentricity = (
  SELECT MAX(eccentricity)
  FROM exoplanets
);
